chunks = [
    "Employees receive 18 casual leaves per year.",
    "The cafeteria opens at 8 am daily.",
    "Leave requests must be approved by your manager.",
]
tests = [
    ("how many leaves do I get", 0),
    ("when does the cafeteria open", 1),
]
correct = 0
for question, expected in tests:
    qw = set(question.lower().split())
    best_i, best_score = 0, -1
    for i, c in enumerate(chunks):
        score = len(qw & set(c.lower().replace(".", "").split()))
        if score > best_score:
            best_score, best_i = score, i
    if best_i == expected:
        correct = correct + 1
        print("hit")
    else:
        print("miss")
print(round(correct / len(tests) * 100), "%")

